import os
import numpy as np
os.chdir('/opt/habitat-lab-src')

import habitat
from habitat.config.default import get_config
from habitat.config import read_write

cfg_path = (
    "/opt/habitat-lab-src/habitat-lab/habitat/config/"
    "benchmark/multi_agent/hssd_spot_human_social_nav.yaml"
)
config = get_config(cfg_path)
with read_write(config):
    config.habitat.simulator.scene_dataset = (
        "/opt/habitat-lab-src/data/hab3_bench_assets/hab3-hssd/"
        "hab3-hssd.scene_dataset_config.json"
    )
    config.habitat.dataset.scenes_dir = "/opt/habitat-lab-src/data/scene_datasets"

with habitat.Env(config=config) as env:
    obs = env.reset()
    print("=== OBS KEYS AND SHAPES ===")
    for k, v in sorted(obs.items()):
        if hasattr(v, 'shape'):
            print(f"  {k}: shape={v.shape}, dtype={v.dtype}, min={v.min():.4f}, max={v.max():.4f}")
        else:
            print(f"  {k}: {v}")

    print("\n=== ACTION SPACE ===")
    print(env.action_space)

    print("\n=== INITIAL METRICS ===")
    metrics = env.get_metrics()
    for k, v in sorted(metrics.items()):
        print(f"  {k}: {v}")

    # Run a few steps with different actions to understand dynamics
    print("\n=== RUNNING 10 STEPS ===")
    for step in range(10):
        # Try moving forward
        gps = obs.get('agent_0_goal_to_agent_gps_compass', None)
        if gps is not None:
            print(f"  Step {step}: gps_compass=[dist={gps[0]:.3f}, angle={gps[1]:.3f}]")

        action = {
            "action": ("agent_0_base_velocity", "agent_1_oracle_nav_randcoord_action"),
            "action_args": {
                "agent_0_base_vel": np.array([1.0, 0.0], dtype=np.float32),
                "agent_1_oracle_nav_randcoord_action": np.array([1.0], dtype=np.float32),
            },
        }
        obs = env.step(action)
        if env.episode_over:
            print("  Episode over!")
            break

    metrics = env.get_metrics()
    print("\n=== METRICS AFTER 10 STEPS ===")
    for k, v in sorted(metrics.items()):
        print(f"  {k}: {v}")

    # Test turning to understand angle convention
    print("\n=== TURNING TEST (positive angular vel) ===")
    for step in range(5):
        gps = obs.get('agent_0_goal_to_agent_gps_compass', None)
        if gps is not None:
            print(f"  Step {step}: gps_compass=[dist={gps[0]:.3f}, angle={gps[1]:.3f}]")
        action = {
            "action": ("agent_0_base_velocity", "agent_1_oracle_nav_randcoord_action"),
            "action_args": {
                "agent_0_base_vel": np.array([0.0, 1.0], dtype=np.float32),
                "agent_1_oracle_nav_randcoord_action": np.array([1.0], dtype=np.float32),
            },
        }
        obs = env.step(action)
        if env.episode_over:
            break

    print("\n=== TURNING TEST (negative angular vel) ===")
    for step in range(5):
        gps = obs.get('agent_0_goal_to_agent_gps_compass', None)
        if gps is not None:
            print(f"  Step {step}: gps_compass=[dist={gps[0]:.3f}, angle={gps[1]:.3f}]")
        action = {
            "action": ("agent_0_base_velocity", "agent_1_oracle_nav_randcoord_action"),
            "action_args": {
                "agent_0_base_vel": np.array([0.0, -1.0], dtype=np.float32),
                "agent_1_oracle_nav_randcoord_action": np.array([1.0], dtype=np.float32),
            },
        }
        obs = env.step(action)
        if env.episode_over:
            break

    print("\nDone exploring!")
